mapper.select:
/* CouponMapper.getAdminCouponList: 관리자 쿠폰 목록 조회 */ SELECT CB.CPN_NO , CB.CPN_NM , CCS.CD_NM AS CPN_STAT_NM , CCG.CD_NM AS CPN_GB_NM , CCT.CD_NM AS CPN_TARGET_NM , CASE WHEN CB.CPN_DOWN_START_DT IS NULL OR CB.CPN_DOWN_START_DT = '0000-00-00 00:00:00' THEN '' ELSE DATE_FORMAT(CB.CPN_DOWN_START_DT, '%Y-%m-%d %H') END AS CPN_DOWN_START_DT , CASE WHEN CB.CPN_DOWN_END_DT IS NULL OR CB.CPN_DOWN_END_DT = '0000-00-00 00:00:00' THEN '' ELSE DATE_FORMAT(CB.CPN_DOWN_END_DT, '%Y-%m-%d %H') END AS CPN_DOWN_END_DT , CB.CPN_DOWN_ABLE_YN , CASE WHEN CB.STAT_STOP_DT IS NULL OR CB.STAT_STOP_DT = '0000-00-00 00:00:00' THEN '' ELSE DATE_FORMAT(CB.STAT_STOP_DT, '%Y-%m-%d %H') END AS STAT_STOP_DT FROM COUPON_BASE CB LEFT JOIN COMMON_CODE CCS ON CCS.GRP_CD = 'CPN_STAT' AND CCS.CD = CB.CPN_STAT_CD LEFT JOIN COMMON_CODE CCG ON CCG.GRP_CD = 'CPN_GB' AND CCG.CD = CB.CPN_GB_CD LEFT JOIN COMMON_CODE CCT ON CCT.GRP_CD = 'CPN_TARGET' AND CCT.CD = CB.CPN_TARGET_CD WHERE IFNULL(CB.DEL_YN, 'N') = 'N'
AND CB.CPN_NO = #{searchValue}
AND CB.CPN_NM LIKE CONCAT(#{searchValue}, '%')
AND CB.REG_DT >= #{searchStartDt}
AND CB.REG_DT <= #{searchEndDt}
AND IFNULL(NULLIF(CB.CPN_DOWN_END_DT, '0000-00-00 00:00:00'), '9999-12-31 23:59:59') >= #{searchStartDt}
AND IFNULL(NULLIF(CB.CPN_DOWN_START_DT, '0000-00-00 00:00:00'), '1000-01-01 00:00:00') <= #{searchEndDt}
AND CB.CPN_STAT_CD = #{cpnStatCd}
AND CB.CPN_GB_CD = #{cpnGbCd}
AND CB.CPN_TARGET_CD = #{cpnTargetCd}
AND CB.CPN_DOWN_ABLE_YN = #{cpnDownAbleYn}
ORDER BY CB.CPN_NO DESC LIMIT #{pageSize} OFFSET #{offset}

/* CouponMapper.getAdminCouponCount: 관리자 쿠폰 목록 건수 조회 */
SELECT COUNT(1)
  FROM COUPON_BASE CB
 WHERE IFNULL(CB.DEL_YN, 'N') = 'N'

  AND CB.CPN_NO = #{searchValue}


  AND CB.CPN_NM LIKE CONCAT(#{searchValue}, '%')


  AND CB.REG_DT >= #{searchStartDt}


  AND CB.REG_DT <= #{searchEndDt}


  AND IFNULL(NULLIF(CB.CPN_DOWN_END_DT, '0000-00-00 00:00:00'), '9999-12-31 23:59:59') >= #{searchStartDt}


  AND IFNULL(NULLIF(CB.CPN_DOWN_START_DT, '0000-00-00 00:00:00'), '1000-01-01 00:00:00') <= #{searchEndDt}


  AND CB.CPN_STAT_CD = #{cpnStatCd}


  AND CB.CPN_GB_CD = #{cpnGbCd}


  AND CB.CPN_TARGET_CD = #{cpnTargetCd}


  AND CB.CPN_DOWN_ABLE_YN = #{cpnDownAbleYn}
